def assess(record: dict) -> str:
    required = {'metric', 'rerun_metric', 'params', 'tolerance', 'case_id', 'seed'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + missing[0]
    meets = not (abs(record["metric"] - record["rerun_metric"]) > record["tolerance"])
    return "PASS" if meets else 'MARK_RUN_NONREPRODUCIBLE'

